search.query:
source="WinEventLog:Microsoft-Windows-Sysmon/Operational" EventCode=3 | rex field=Message "Image:\s*(?<Image>[^
]+)" | rex field=Message "DestinationIp:\s*(?<DestIp>[^
]+)" | rex field=Message "DestinationPort:\s*(?<DestPort>[^
]+)" | rex field=Message "User:\s*(?<User>[^
]+)" | search Image="*\Temp\*" OR Image="*\AppData\*" OR Image="*\ProgramData\*" | table _time host User Image DestIp DestPort | sort - _time

source="WinEventLog:Microsoft-Windows-Windows Defender/Operational" (EventCode=1116 OR EventCode=1117) | rex field=Message "Threat Name:\s+(?<Threat>[^
]+)" | rex field=Message "Action:\s+(?<Action>[^
]+)" | rex field=Message "Path:\s+(?<Path>[^
]+)" | table _time host Threat Action Path | sort - _time
